#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=105;
int n,a[N];
int dfn[N],low[N],cnt2;
stack<int> st;
int vis[N],cnt,ru[N],chu[N];
vector<int> g[N];
void tarjan(int u)
{
//	cout<<u<<"\n---------------\n";
	low[u]=dfn[u]=++cnt;
	st.push(u);
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
//		cout<<u<<" -> "<<v<<"\n";
		if(!dfn[v])
		{
			tarjan(v);
			low[u]=min(low[u],low[v]);
		}
		else if(vis[v])
		{
			low[u]=min(low[u],dfn[v]);
		}
	}
//	cout<<u<<"\n__________\n";
	if(low[u]==dfn[u])
	{
//		cout<<"aaaa : ";
		cnt2++;
		int v;
		while(v=st.top())
		{
//			cout<<v;
			vis[v]=cnt2;
			st.pop();
			if(v==u) break;
//			cout<<" , ";
		}
//		cout<<"\n";
	}
}
int main()
{
	ios::sync_with_stdio(false);
	cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		int num;
		while(cin>>num)
		{
			if(num==0) break;
			g[i].push_back(num);
//			cout<<i<<" -> "<<num<<"\n";
		}
	}
	for(int i=1;i<=n;i++)
	{
		if(!dfn[i]) tarjan(i);
//		dbg(vis[i]);
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=0;j<g[i].size();j++) 
		{
			int jj=g[i][j];
			if(vis[i]!=vis[jj])
			{
				ru[vis[jj]]++;
				chu[vis[i]]++;
			}
		}
	}
	int r=0,c=0;
	for(int i=1;i<=cnt2;i++)
	{
		if(ru[i]==0) r++;
		if(chu[i]==0) c++;
	}
//	cout<<r<<" "<<c<<"\n";
	cout<<max(1,r)<<"\n"<<max(r,c);

	return 0;
}
